const base64Data   = $input.first().json.base64data;
const body = $('Invoice Audit Webhook').first().json.body || {};
const fileName = body.file_name || 'invoice.pdf';
const fileId = body.file_id || '';
const prompt = 'You are an invoice auditor. Analyze this invoice PDF.\nReturn ONLY a raw JSON object with no markdown and no code fences.\nFields: vendor_name (string or null), invoice_number (string or null), invoice_date (YYYY-MM-DD or null), due_date (YYYY-MM-DD or null), line_items_count (integer or null), total_amount (number or null), currency (3-letter ISO code or null), has_signature (boolean), signature_valid (boolean - true ONLY for handwritten ink or rubber stamp not printed names), confidence_score (float 0.0 to 1.0), errors (array - include: No signature found, Total amount missing, Not a valid invoice, Invoice number missing - whichever apply), warnings (array - include: Due date has passed, Currency unclear - whichever apply). Return ONLY the JSON.';
const payload = { contents: [{ parts: [{ inline_data: { mime_type: 'application/pdf', data: base64Data } }, { text: prompt }] }], generationConfig: { temperature: 0.0, maxOutputTokens: 2048 } };
return [{ json: { payload, file_name: fileName, file_id: fileId } }];

const geminiOutput=$input.first().json;
const fileMeta=$('Build Gemini Payload').first().json;
let parsed;
try{
  const raw=geminiOutput.candidates[0].content.parts[0].text;
  const start=raw.indexOf('{');const end=raw.lastIndexOf('}');
  if(start===-1||end===-1)throw new Error('No JSON in response');
  parsed=JSON.parse(raw.slice(start,end+1));
}catch(e){
  parsed={vendor_name:null,invoice_number:null,invoice_date:null,due_date:null,line_items_count:null,total_amount:null,currency:null,has_signature:false,signature_valid:false,confidence_score:0,errors:['AI parse failure: '+e.message],warnings:[]};
}
return [{json:{file_name:String(fileMeta.file_name||''),file_id:String(fileMeta.file_id||''),vendor_name:parsed.vendor_name||null,invoice_number:String(parsed.invoice_number||''),invoice_date:parsed.invoice_date||null,due_date:parsed.due_date||null,line_items_count:parsed.line_items_count||null,total_amount:(parsed.total_amount!==undefined&&parsed.total_amount!==null)?Number(parsed.total_amount):null,currency:parsed.currency||null,has_signature:Boolean(parsed.has_signature),signature_valid:Boolean(parsed.signature_valid),confidence_score:Math.min(1,Math.max(0,Number(parsed.confidence_score)||0)),errors:Array.isArray(parsed.errors)?parsed.errors:[],warnings:Array.isArray(parsed.warnings)?parsed.warnings:[],processed_at:new Date().toISOString(),source:'webhook'}}];

// Get rows from BOTH sheets for duplicate scanning
const verifiedRows = $('Read Verified Sheet').all().map(i => i.json).filter(r => r.invoice_number);
const flaggedRows = $input.all().map(i => i.json).filter(r => r.invoice_number);
const allRows = [...verifiedRows, ...flaggedRows];

// Current invoice being processed
const auditData = $('Parse Analysis Result').first().json;
const invNum = String(auditData.invoice_number || '').toLowerCase().trim();
const vendor = String(auditData.vendor_name || '').toLowerCase().trim();

let is_duplicate = false;
let duplicate_ref = null;

if (invNum.length > 2 && vendor.length > 2) {
  const match = allRows.find(r =>
    String(r.invoice_number || '').toLowerCase().trim() === invNum &&
    String(r.vendor_name || '').toLowerCase().trim() === vendor
  );
  if (match) {
    is_duplicate = true;
    duplicate_ref = match.file_name || 'previous submission';
  }
}

const errors = [...(auditData.errors || [])];
if (is_duplicate) errors.push('Possible duplicate of: ' + duplicate_ref);

return [{ json: { ...auditData, is_duplicate, duplicate_ref: duplicate_ref || null, errors } }];

const d = $input.first().json;
let status = 'verified';
if (d.errors.length > 0) status = 'flagged';
else if (d.confidence_score < 0.75) status = 'needs_review';
return [{ json: {
  ...d,
  audit_status: status,
  _response: {
    status,
    file_name:        d.file_name,
    vendor_name:      d.vendor_name,
    invoice_number:   d.invoice_number,
    invoice_date:     d.invoice_date,
    due_date:         d.due_date,
    total_amount:     d.total_amount,
    currency:         d.currency,
    has_signature:    d.has_signature,
    signature_valid:  d.signature_valid,
    confidence_score: d.confidence_score,
    is_duplicate:     d.is_duplicate,
    errors:           d.errors,
    warnings:         d.warnings,
    processed_at:     d.processed_at
  }
} }];

const d = $('Check for Duplicate').first().json;
const fileId = d.file_id || '';
const driveUrl = 'https://drive.google.com/file/d/' + fileId + '/view';
const confidence = Math.round((d.confidence_score||0)*100);
const amount = (d.total_amount!==null&&d.total_amount!==undefined)?(d.currency||'')+' '+d.total_amount:'Not found';
const dupLabel = d.is_duplicate?' [DUPLICATE]':'';
const errRows = (d.errors||[]).map(e=>'<li style="color:#c04828;margin:4px 0">'+e+'</li>').join('');
const warnRows = (d.warnings||[]).length?'<p><b>Warnings:</b></p><ul>'+(d.warnings||[]).map(w=>'<li style="color:#e67e22;margin:4px 0">'+w+'</li>').join('')+'</ul>':'';
const html = '<div style="font-family:Arial,sans-serif;max-width:580px"><div style="background:#c04828;padding:18px 24px;border-radius:8px 8px 0 0"><h2 style="color:#fff;margin:0;font-size:16px">Invoice Flagged'+dupLabel+' (On-Demand API)</h2></div><div style="padding:20px 24px;border:1px solid #ddd;border-top:none"><table style="width:100%"><tr><td style="color:#666;padding:4px 12px 4px 0">File</td><td style="font-weight:700">'+(d.file_name||'Unknown')+'</td></tr><tr><td style="color:#666;padding:4px 12px 4px 0">Vendor</td><td>'+(d.vendor_name||'Not identified')+'</td></tr><tr><td style="color:#666;padding:4px 12px 4px 0">Invoice #</td><td>'+(d.invoice_number||'Not found')+'</td></tr><tr><td style="color:#666;padding:4px 12px 4px 0">Amount</td><td>'+amount+'</td></tr><tr><td style="color:#666;padding:4px 12px 4px 0">AI Confidence</td><td>'+confidence+'%</td></tr></table><p><b>Problems found:</b></p><ul>'+errRows+'</ul>'+warnRows+'<p><a href="'+driveUrl+'" style="display:inline-block;background:#0f6e56;color:#fff;padding:10px 20px;text-decoration:none;border-radius:6px">Open in Google Drive</a></p><p style="font-size:11px;color:#aaa">Processed: '+d.processed_at+' | Source: webhook</p></div></div>';
return [{json:{subject:(d.is_duplicate?'[DUPLICATE] ':'[FLAGGED] ')+(d.file_name||'Invoice')+' (API)',html}}];

